window.SmartRisk=window.SmartRisk||{};SmartRisk.Table={create({containerId,columns,rows,onAction=null}){const root=document.getElementById(containerId),state={query:"",sortKey:columns[0].key,sortDirection:"asc"};function status(v){const c=SmartRisk.Utils.normalizeText(v).includes("ajuste")?"badge-warning":"badge-success";return `<span class="badge ${c}">${v}</span>`}function render(){let data=rows.filter(r=>SmartRisk.Utils.normalizeText(columns.map(c=>r[c.key]).join(" ")).includes(SmartRisk.Utils.normalizeText(state.query)));data.sort((a,b)=>{const x=String(a[state.sortKey]).localeCompare(String(b[state.sortKey]),"es",{numeric:true});return state.sortDirection==="asc"?x:-x});root.querySelector("tbody").innerHTML=data.map(r=>`<tr>${columns.map(c=>{const v=r[c.key];if(c.type==="status")return `<td>${status(v)}</td>`;if(c.type==="percent")return `<td><div class="territory-progress"><strong>${v}%</strong><div class="territory-progress-track"><div class="territory-progress-value" style="width:${v}%"></div></div></div></td>`;if(c.type==="action")return `<td><button class="icon-btn" data-action="${r.id}" title="Ver detalle">${SmartRisk.Icon.render("eye",17)}</button></td>`;return `<td>${SmartRisk.Utils.escapeHtml(v)}</td>`}).join("")}</tr>`).join("")||`<tr><td colspan="${columns.length}" class="muted">Sin resultados.</td></tr>`;root.querySelectorAll("[data-action]").forEach(b=>b.onclick=()=>onAction?.(b.dataset.action))}root.innerHTML=`<div class="table-wrap"><table class="data-table"><thead><tr>${columns.map(c=>`<th><button class="table-sort" data-sort="${c.key}">${c.label}</button></th>`).join("")}</tr></thead><tbody></tbody></table></div>`;root.querySelectorAll("[data-sort]").forEach(b=>b.onclick=()=>{state.sortDirection=state.sortKey===b.dataset.sort&&state.sortDirection==="asc"?"desc":"asc";state.sortKey=b.dataset.sort;render()});render();return{search(q){state.query=q;render()}}}};